---@class LBlockMiniGameHurtActor
local LBlockMiniGameHurtActor = LxClass("LBlockMiniGameHurtActor", nil)

function LBlockMiniGameHurtActor:LBlockMiniGameHurtActor(obj)
    self._obj = obj

    self._trans = self._obj:GetTransform()

    -- 需要播放的列表
    self._needPlayList = {}

    -- 特效列表
    self._effList = {}

    -- 销毁
    self._isDestroy = false
end

-- 销毁
function LBlockMiniGameHurtActor:Destroy()
    self._isDestroy = true

    for k, v in pairs(self._effList) do
        v.dp:Destroy()
    end
end

-- 销毁
function LBlockMiniGameHurtActor:IsDestroy()
    return self._isDestroy
end

-- Update
function LBlockMiniGameHurtActor:Update(dt)
    for i = #self._needPlayList, 1, -1 do
        local tab = self._needPlayList[i]
        tab.startTime = tab.startTime - dt
        if tab.startTime <= 0 then
            table.remove(self._needPlayList, i)
            self:PlayEffect(tab)
        end
    end

    for i = #self._effList, 1, -1 do
        local tab = self._effList[i]
        tab.endTime = tab.endTime - dt
        if tab.endTime <= 0 then
            table.remove(self._effList, i)
            tab.dp:Destroy()
        end
    end
end

-- 受击
function LBlockMiniGameHurtActor:DoHurt(resName, startTime, endFunc)
    table.insert(self._needPlayList, { resName = resName, startTime = startTime, endFunc = endFunc })
end

-- 播特效
function LBlockMiniGameHurtActor:PlayEffect(tab)
    if tab.endFunc then
        tab.endFunc()
    end
    if tab.resName == "" then
        return
    end

    local resName = tab.resName
    local dp = LDisplayEffect:New()
    dp:CreateEffect(self._trans, resName)
    dp:SetResTag(CS.RES_TAG_SCENE)
    table.insert(self._effList, { dp = dp, endTime = 0.3 })
    dp:SetLoadedFunction(function()
        if self:IsDestroy() then
            return
        end

        -- self:OnEffectLoaded()
        local trans = dp:GetDisplayTrans()
        trans.localPosition = Vector3(0, 0.5, 0)
        trans.localScale = Vector3(0.3, 0.3, 0.3)
        self:UpDateFlipX()
    end)

    dp:StartLoadEffect()
end

-- 翻转X轴
function LBlockMiniGameHurtActor:UpDateFlipX()
    local flipX = self._obj:GetDpObject():IsFlipX()
    for k, v in pairs(self._effList) do
        if v.dp then
            local trans = v.dp:GetDisplayTrans()
            if trans then
                local scale = trans.localScale
                scale.x = math.abs(scale.x)
                if flipX then
                    scale.x = -scale.x
                    trans.localScale = scale
                else
                    trans.localScale = scale
                end
            end
        end
    end
end

-- 暂停
function LBlockMiniGameHurtActor:OnPauseGame()

end

-- 恢复
function LBlockMiniGameHurtActor:OnResumeGame()

end

return LBlockMiniGameHurtActor
